import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for the fix of issue: ")" unexpectedly indented in expression but not in `if`
 *
 * The expected behavior for `ktlint_official` code style is that the closing parenthesis
 * of a parenthesized expression should align with the opening parenthesis, consistent
 * with how the condition parentheses in if statements are handled.
 */
class ParenthesizedExpressionIndentTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given ktlint_official code style and parenthesized expression inside if block`() {
        // This is the exact scenario from the issue
        val code =
            """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given ktlint_official code style and parenthesized expression inside if with multiline condition`() {
        // This is the second scenario from the issue showing that if conditions align properly
        // but parenthesized expressions inside the block do not
        val code =
            """
            fun foo(): Boolean {
                if (
                    condition1
                ) {
                    (
                        condition2
                    )
                } else {
                    condition3
                }
                return true
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given ktlint_official code style and standalone parenthesized expression`() {
        val code =
            """
            val foo = (
                1 + 2
            )
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given ktlint_official code style and parenthesized expression inside block`() {
        val code =
            """
            fun foo() {
                val x = (
                    1 + 2
                )
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given ktlint_official code style and nested parenthesized expressions`() {
        val code =
            """
            val foo = (
                (
                    1 + 2
                ) + 3
            )
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}"}
